// Function Expression sintaksisi
const funksiyaAdi = function(parametr1, parametr2) {
  // funksiyanın kodu
  return nəticə;
};

// 'vur' adlı funksiyanı dəyişənə qoyuram
const vur = function(a, b) {
  return a * b;
};

// Funksiyanı çağırıram
console.log(vur(4, 5)); // nəticə: 20
console.log(vur(3, 7)); // nəticə: 21

// 'salamVer' adlı funksiyanı dəyişənə qoyuram
const salamVer = function(ad) {
  return 'Salam, ' + ad + '!';
};

// Funksiyanı çağırıram
console.log(salamVer('Aysel')); // nəticə: Salam, Aysel!
console.log(salamVer('Kamran')); // nəticə: Salam, Kamran!

// Anonim funksiya - öz adı yoxdur
const kvadrat = function(x) {
  return x * x;
};

// Funksiyanın adını yoxlayaq
console.log(kvadrat.name); // nəticə: kvadrat (dəyişənin adı)
console.log(kvadrat(5)); // nəticə: 25

// Bu xəta verəcək - funksiya hələ təyin olunmayıb
// console.log(cix(10, 3)); // ReferenceError

// Əvvəlcə funksiyanı təyin edirəm
const cix = function(a, b) {
  return a - b;
};

// İndi istifadə edə bilərəm
console.log(cix(10, 3)); // nəticə: 7

// const ilə - funksiya dəyişməz
const topla = function(a, b) {
  return a + b;
};

// let ilə - funksiyanı dəyişə bilərəm
let salam = function(ad) {
  return 'Salam, ' + ad;
};

// Funksiyanı dəyişdirirəm
salam = function(ad) {
  return 'Merhaba, ' + ad;
};

console.log(topla(2, 3)); // nəticə: 5
console.log(salam('Dünya')); // nəticə: Merhaba, Dünya

// Massiv
const ədədlər = [1, 2, 3, 4, 5];

// Function Expression callback kimi
const kvadratlar = ədədlər.map(function(ədəd) {
  return ədəd * ədəd;
});

console.log(kvadratlar); // nəticə: [1, 4, 9, 16, 25]

// Cüt ədədləri tapmaq
const cütƏdədlər = ədədlər.filter(function(ədəd) {
  return ədəd % 2 === 0;
});

console.log(cütƏdədlər); // nəticə: [2, 4]

// Function Declaration - hoisting var
function topla(a, b) {
  return a + b;
}

// Function Expression - hoisting yoxdur
const toplaExpr = function(a, b) {
  return a + b;
};

// Nəticə eynidir
console.log(topla(2, 3)); // nəticə: 5
console.log(toplaExpr(2, 3)); // nəticə: 5

