// Öz Function Expression funksiyalarını yarat!
const kub = function(x) {
  return x * x * x;
};

const faktorial = function(n) {
  if (n <= 1) return 1;
  return n * faktorial(n - 1);
};

// Funksiyaları test et!
console.log(kub(3));
console.log(faktorial(5));
